fun solve(weight: Array<Long>): Long {
    val n = weight.size
    val maxWeight = LongArray(n)
    maxWeight[0] = weight[0]
    for (i in 1 until n) {
        maxWeight[i] = maxOf(maxWeight[i - 1], weight[i])
    }

    val balanceShipments = mutableListOf<Pair<Int, Int>>()

    for (i in 0 until n) {
        var left = 0L
        var right = i.toLong()
        var res = -1
        while (left <= right) {
            val mid = (left + right) / 2
            if (maxWeight[mid.toInt()] > weight[i]) {
                res = mid.toInt()
                right = mid - 1
            } else {
                left = mid + 1
            }
        }
        if (res != -1) {
            balanceShipments.add(Pair(res, i))
        }
    }

    balanceShipments.sortBy { it.second }

    var count = 0L
    var lastEnd = -1
    for ((start, end) in balanceShipments) {
        if (start > lastEnd) {
            count++
            lastEnd = end
        }
    }

    return count
}
